import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import API from "../api";

const Home = () => {
  const [events, setEvents] = useState([]);

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const res = await API.get("/events");
        setEvents(res.data.events);
      } catch (err) {
        console.log(err);
      }
    };
    fetchEvents();
  }, []);

  return (
    <div className="container mx-auto p-6">
      <h1 className="text-4xl font-bold mb-6">Upcoming Events</h1>
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
        {events.map(event => (
          <div key={event._id} className="bg-white shadow rounded-lg overflow-hidden">
            <img src={event.image} className="w-full h-48 object-cover" />
            <div className="p-4">
              <h2 className="font-bold text-xl">{event.name}</h2>
              <p className="text-gray-600">{new Date(event.date).toLocaleDateString()} - {event.venue}</p>
              <p className="mt-2 text-purple-600 font-semibold">${event.price}</p>
              <Link to={`/events/${event._id}`} className="mt-4 inline-block bg-purple-600 text-white px-4 py-2 rounded">View & Book</Link>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Home;
